            </div>

            <div className="ai-topbar__controls">
              <Select onValueChange={setModel} value={model}>
                <SelectTrigger className="w-[11rem]" size="sm">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectGroup>
                    {capabilities.models.map((option) => (
                      <SelectItem key={option.id} value={option.id}>
