function TimelineEventView({
  event,
  isSelected,
  onSelect,
}: {
  event: TimelineEvent
  isSelected: boolean
  onSelect: () => void
}) {
  if (event.kind === 'message') {
    return <MessageTurn event={event} />
  }

  return <OperationalTurn event={event} isSelected={isSelected} onSelect={onSelect} />
}

function MessageTurn({ event }: { event: MessageEvent }) {
